// Normalize incoming data
// Accepts: { account_id, transcript } or { account_id, transcript_path }
const body = $input.first().json.body || $input.first().json;
const accountId = body.account_id || `acct_${Date.now()}`;
const transcript = body.transcript || '';

if (!transcript) {
  throw new Error('transcript field is required');
}

return [{ json: { account_id: accountId, transcript, stage: 'pipeline_a' } }];

const response = $input.first().json;
const accountId = $('Normalize Input').first().json.account_id;
const content = response.content[0].text;

// Strip markdown fences
const clean = content.replace(/```json\n?/g, '').replace(/```/g, '').trim();
let extracted;
try {
  extracted = JSON.parse(clean);
} catch (e) {
  extracted = { parse_error: e.message, raw: clean };
}

// Build full memo
const memo = {
  account_id: accountId,
  version: 'v1',
  created_at: new Date().toISOString(),
  updated_at: new Date().toISOString(),
  _pipeline: 'demo_call',
  ...extracted
};

return [{ json: memo }];

const memo = $input.first().json;
const company = memo.company_name || 'Clara Client';
const bh = memo.business_hours || {};
const days = (bh.days || []).join(', ') || 'Monday through Friday';
const start = bh.start || '08:00';
const end = bh.end || '17:00';
const tz = bh.timezone || 'local time';
const hoursStr = `${days}, ${start}–${end} ${tz}`;
const emergencyList = (memo.emergency_definition || ['active fire system event']).join(', ');
const routing = memo.emergency_routing_rules || {};
const primary = routing.primary_contact || '[ON-CALL NUMBER]';
const timeout = routing.timeout_seconds || 60;
const constraints = (memo.integration_constraints || []).map(c => `- ${c}`).join('\n');

const systemPrompt = `You are Clara, a professional AI voice assistant for ${company}.

BUSINESS HOURS: ${hoursStr}
SERVICES: ${(memo.services_supported || []).join(', ')}

DURING HOURS FLOW:
1. Greet: "Thank you for calling ${company}. This is Clara. How can I help you?"
2. Understand purpose - classify as emergency or non-emergency
3. Collect name and callback number
4. Transfer to appropriate team. Say: "Let me connect you. Please hold."
5. If transfer fails after ${timeout}s: apologize and confirm callback within 30 minutes
6. Ask if anything else needed. Close warmly.

AFTER HOURS FLOW:
1. Greet and state hours: "You've reached ${company}. We're outside business hours (${hoursStr}). This is Clara."
2. Ask purpose. Confirm if emergency.
3. EMERGENCY TRIGGERS: ${emergencyList}
4. IF EMERGENCY: Collect name, number, address immediately. Attempt transfer to: ${primary}
   - Timeout: ${timeout}s then escalate per routing rules
   - If all fail: "Your information is logged as emergency. A technician calls back within 15 min. If life-threatening, call 911."
5. IF NON-EMERGENCY: Collect name, number, issue. Confirm next-business-day followup.
6. Ask if anything else. Close warmly.

RULES:
- Never mention function calls, tools, or internal systems to callers
- Never say "your call is important to us"
- Always collect: name + phone for any routing action
- For emergencies also collect: address/location
${constraints ? '\nSYSTEM CONSTRAINTS (internal only):\n' + constraints : ''}`;

const spec = {
  agent_name: `${company} - Clara Agent`,
  version: 'v1',
  generated_at: new Date().toISOString(),
  source_account_id: memo.account_id,
  voice_style: { voice_id: 'elevenlabs-rachel', speed: 1.0 },
  system_prompt: systemPrompt,
  key_variables: {
    timezone: bh.timezone,
    business_hours_start: bh.start,
    business_hours_end: bh.end,
    business_days: bh.days,
    emergency_routing_primary: primary,
    transfer_timeout_seconds: timeout
  },
  call_transfer_protocol: {
    method: 'warm_transfer',
    announce_script: 'Let me connect you with the right person. Please hold.',
    timeout_seconds: timeout
  },
  fallback_protocol: {
    trigger: 'transfer_fails',
    script: 'I was unable to reach the on-call team. Your information has been logged and someone will call you back within 15 minutes.'
  },
  integration_constraints: memo.integration_constraints || [],
  questions_or_unknowns: memo.questions_or_unknowns || []
};

return [{ json: { memo, spec } }];
